      "reversibility": "easy"
    },
    {
      "id": "d3",
      "decision": "Use renderWithProviders from helpers.tsx for consistency with other tests",
      "based_on": ["q2"],
      "alternatives_rejected": ["Render with just QueryClientProvider", "Render without providers since hooks are mocked"],
      "reversibility": "easy"
    },
    {
      "id": "d4",
      "decision": "Use small fixture values (<1000) for numeric fields where possible; use value.toLocaleString() in assertions for larger numbers",
      "based_on": ["q4", "a6"],
      "alternatives_rejected": ["Regex matchers for locale output", "Mock toLocaleString globally"],
      "reversibility": "easy"
    },
    {
      "id": "d5",
      "decision": "Create fixtures with and without optional fields (compile_time_ms, memory_bytes, last_updated) to cover all conditional branches",
      "based_on": ["q1"],
      "alternatives_rejected": ["Single fixture with all fields present", "Parameterized test matrix"],
      "reversibility": "easy"
    }
  ],
  "steps": [
    {
      "step": 1,
      "task": "Create test file at frontend/src/__tests__/JunctionTreePanel.test.tsx with imports: vi, render utilities from helpers.tsx, screen/waitFor from @testing-library/react, the JunctionTreePanel component, and useEngineStats from @/lib/query/hooks",
      "depends_on": []
    },
    {
      "step": 2,
      "task": "Set up vi.mock('@/lib/query/hooks') with a factory that returns mockUseEngineStats for useEngineStats, and create a mockUseEngineStats vi.fn() variable",
      "depends_on": [1]
    },
    {
      "step": 3,
      "task": "Create test fixtures: fullDiagnosticsData (all fields present including optional ones), minimalDiagnosticsData (no optional fields), and errorCountData (error_count > 0 for warning color test)",
      "depends_on": [2]
    },
    {
      "step": 4,
      "task": "Write test: loading state - mock returns { data: undefined, isLoading: true }, assert loading indicator is shown",
      "depends_on": [3]
