    {
      "step": 5,
      "task": "Write test: renders clique tree stats (cliques count, max_clique_size, states via toLocaleString) when data is loaded",
      "depends_on": [3]
    },
    {
      "step": 6,
      "task": "Write test: renders inference diagnostics (request_count, avg_inference_ms, error_count) when data is loaded",
      "depends_on": [3]
